#include<bits/stdc++.h>
using namespace std;
struct node {
	int l,w;
} a[11000];
int n;
int dp[11000]= {0},ans;
bool cmp(node x,node y) {
	if(x.l==y.l) return x.w<y.w; 
	return x.l<y.l;
}
int main() {
	cin>>n;
	for(int i=1; i<=n; i++) cin>>a[i].l>>a[i].w; 
	sort(a+1,a+1+n,cmp);
	for(int i=2; i<=n; i++) { 
		for(int j=1; j<i; j++) {
			if(a[j].w>a[i].w) {
				dp[i]=max(dp[j]+1,dp[i]);
			}
		}
		ans=max(dp[i],ans);
	}
	cout<<ans+1; 
	return 0;
}
